import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { booksAPI, finesAPI, libraryCardsAPI, issuesAPI } from '../services/api';

// ================= HELPERS =================

const normalizeAPIResponse = (response) => {
  if (!response) return [];

  const data = response?.data;

  if (data && typeof data === "object" && Array.isArray(data.data)) {
    return data.data;
  }

  if (Array.isArray(data)) return data;

  if (data && typeof data === "object") return [data];

  return [];
};

const ensureArray = (value) => {
  if (Array.isArray(value)) return value;
  if (!value) return [];
  return [value];
};

const safeNumber = (value, fallback = 0) => {
  const num = Number(value);
  return isNaN(num) ? fallback : num;
};

const calculateTotalFines = (fines) => {
  return ensureArray(fines).reduce((sum, fine) => {
    if (!fine) return sum;
    const amount =
      fine.fineAmount ??
      fine.amount ??
      fine.fine ??
      fine.totalFine ??
      0;
    return sum + safeNumber(amount);
  }, 0);
};

// ================= COMPONENTS =================

const StatCard = ({ icon, color, value, label }) => (
  <div className="col-sm-6 col-lg-3">
    <div className="stat-card">
      <div className={`stat-icon ${color}`}>
        <i className={`bi ${icon}`}></i>
      </div>
      <div>
        <div className="stat-value">{value ?? 0}</div>
        <div className="stat-label">{label}</div>
      </div>
    </div>
  </div>
);

const QuickAction = ({ to, icon, label, color }) => (
  <Link to={to} className="lib-card p-3 d-flex align-items-center gap-3 text-decoration-none">
    <div className={`stat-icon ${color}`}>
      <i className={`bi ${icon}`}></i>
    </div>
    <span>{label}</span>
  </Link>
);

// ================= MAIN =================

const DashboardPage = () => {
  const { currentUser } = useAuth();
  const role = currentUser?.role;

  const [loading, setLoading] = useState(true);
  const [data, setData] = useState({
    books: [],
    fines: [],
    requests: [],
    myCard: null,
    issues: []
  });

  useEffect(() => {
    const fetchData = async () => {
      try {
        const booksRes = await booksAPI.getAll();
        const finesRes = role === "Student"
          ? await finesAPI.getMyFines()
          : await finesAPI.getAll();

        const cardsRes = role === "Student"
          ? await libraryCardsAPI.getMyCard().catch(() => ({ data: null }))
          : await libraryCardsAPI.getAll();

        const issuesRes = await issuesAPI.getAll();

        setData({
          books: ensureArray(normalizeAPIResponse(booksRes)),
          fines: ensureArray(normalizeAPIResponse(finesRes)),
          requests: ensureArray(normalizeAPIResponse(cardsRes)),
          issues: ensureArray(normalizeAPIResponse(issuesRes)),
          myCard: normalizeAPIResponse(cardsRes)
        });

      } catch (err) {
        console.error("Dashboard error:", err);
      } finally {
        setLoading(false);
      }
    };

    if (role) fetchData();
  }, [role]);

  if (loading) return <div className="text-center py-5">Loading...</div>;

  const books = ensureArray(data.books);
  const fines = ensureArray(data.fines);
  const issues = ensureArray(data.issues);
  const requests = ensureArray(data.requests);

  const unpaidFines = fines.filter(f => (f?.status || "").toLowerCase() === "unpaid");

  const availableBooks = books.filter(b => {
    const copies =
      b?.availableCopies ??
      b?.available ??
      b?.quantity ??
      0;
    return Number(copies) > 0;
  }).length;

  const activeIssues = issues.filter(i => !i?.returnDate);
  const totalFines = calculateTotalFines(unpaidFines);

  return (
    <div className="container mt-4">
      <h3>Hello, {currentUser?.name}</h3>

      <div className="row">
        <StatCard icon="bi-book" color="red" value={availableBooks} label="Books Available" />
        <StatCard icon="bi-cash" color="green" value={`₹${totalFines}`} label="Unpaid Fines" />
        <StatCard icon="bi-list" color="blue" value={activeIssues.length} label="Active Issues" />
      </div>

      <div className="mt-4">
        <QuickAction to="/books" icon="bi-book" label="Browse Books" color="red" />
        <QuickAction to="/fines" icon="bi-cash" label="View Fines" color="green" />
      </div>
    </div>
  );
};

export default DashboardPage;
